import random
import time
from flask import Flask, request, abort, jsonify
from prometheus_client import generate_latest, Histogram, Counter, Gauge

app = Flask(__name__)

# Prometheus Metrics
# Counter: Total number of requests
REQUEST_COUNT = Counter(
    'http_requests_total', 'Total HTTP Requests',
    ['method', 'endpoint', 'status_code']
)

# Histogram: Request latency
REQUEST_LATENCY = Histogram(
    'http_request_duration_seconds', 'HTTP Request Latency',
    ['method', 'endpoint']
)

# Gauge: Number of concurrent requests
IN_PROGRESS_REQUESTS = Gauge(
    'http_requests_in_progress', 'Number of in-progress HTTP requests',
    ['method', 'endpoint']
)

# Counter: Example business logic metric - successful operations
BUSINESS_SUCCESS_OPERATIONS_TOTAL = Counter(
    'business_success_operations_total', 'Total successful business operations'
)

# Gauge: Example business logic metric - current stock level
CURRENT_STOCK_LEVEL = Gauge(
    'business_current_stock_level', 'Current stock level of a product'
)

# Histogram: Example business logic metric - processing time for an item
ITEM_PROCESSING_DURATION_SECONDS = Histogram(
    'business_item_processing_duration_seconds', 'Duration of processing a single item'
)


@app.before_request
def before_request_hook():
    method = request.method
    endpoint = request.path
    IN_PROGRESS_REQUESTS.labels(method=method, endpoint=endpoint).inc()
    request.start_time = time.time()  # Store start time for latency calculation


@app.after_request
def after_request_hook(response):
    method = request.method
    endpoint = request.path
    status_code = response.status_code

    # Decrement in-progress requests
    IN_PROGRESS_REQUESTS.labels(method=method, endpoint=endpoint).dec()

    # Increment total request count
    REQUEST_COUNT.labels(method=method, endpoint=endpoint, status_code=status_code).inc()

    # Observe request latency
    if hasattr(request, 'start_time'):
        latency = time.time() - request.start_time
        REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(latency)

    return response


@app.route('/')
def home():
    time.sleep(random.uniform(0.01, 0.1)) # Simulate some work
    return 'Hello, Flask with Prometheus!'

@app.route('/slow')
def slow_endpoint():
    sleep_time = random.uniform(0.1, 0.5)
    time.sleep(sleep_time)
    BUSINESS_SUCCESS_OPERATIONS_TOTAL.inc() # Simulate a business operation
    return f'This was a slow request, slept for {sleep_time:.2f} seconds.'

@app.route('/items/<item_id>')
def get_item(item_id):
    processing_start_time = time.time()
    # Simulate processing an item
    time.sleep(random.uniform(0.05, 0.2))
    processing_duration = time.time() - processing_start_time
    ITEM_PROCESSING_DURATION_SECONDS.observe(processing_duration)

    stock_level = random.randint(0, 100)
    CURRENT_STOCK_LEVEL.set(stock_level) # Update stock level gauge

    return jsonify({"item_id": item_id, "status": "processed", "stock": stock_level})

@app.route('/error')
def error_endpoint():
    abort(500, description="This is an intentional error")


@app.route('/metrics')
def metrics():
    # Return Prometheus metrics
    return generate_latest(), 200, {'Content-Type': 'text/plain; charset=utf-8'}

if __name__ == '__main__':
    # Initial setup for a gauge if it's a fixed value or needs to be set once
    CURRENT_STOCK_LEVEL.set(50) # Set an initial stock level
    app.run(host='0.0.0.0', port=5000)